const src = $input.first()?.json || {};
const query = (src.query && typeof src.query === 'object') ? src.query : src;

const mode = String(query['hub.mode'] ?? query.hub_mode ?? query.mode ?? '').trim();
const verifyToken = String(query['hub.verify_token'] ?? query.hub_verify_token ?? query.verify_token ?? '').trim();
const challenge = String(query['hub.challenge'] ?? query.hub_challenge ?? query.challenge ?? '').trim();

const expectedToken = String($env.WHATSAPP_VERIFY_TOKEN || '').trim();

const valid = Boolean(
  mode === 'subscribe' &&
  challenge &&
  expectedToken &&
  verifyToken === expectedToken
);

return [{
  json: {
    valid,
    challenge,
    mode,
    error: valid ? '' : 'invalid verify token, mode, or challenge',
  },
}];

function messageTextFromMessage(msg) {
  if (!msg || typeof msg !== 'object') return '';
  const type = msg.type || '';

  if (type === 'text') return String(msg.text?.body || '').trim();
  if (type === 'button') return String(msg.button?.text || '').trim();
  if (type === 'interactive') {
    const replyId = msg.interactive?.button_reply?.id || msg.interactive?.list_reply?.id || '';
    const replyTitle = msg.interactive?.button_reply?.title || msg.interactive?.list_reply?.title || '';
    return String(replyTitle || replyId || '').trim();
  }
  if (type === 'image') return '[imagem]';
  if (type === 'document') return '[documento]';
  if (type === 'audio') return '[audio]';
  if (type === 'video') return '[video]';

  return String(msg.caption || '').trim();
}

const input = $input.first()?.json || {};
const out = [];
const entries = Array.isArray(input.entry) ? input.entry : [];

for (const entry of entries) {
  const changes = Array.isArray(entry?.changes) ? entry.changes : [];
  for (const change of changes) {
    const value = change?.value || {};
    const phoneNumberId = String(value?.metadata?.phone_number_id || '').trim();
    const tenantId = String(input.tenant_id || $env.LARA_TENANT_ID || 'default').trim() || 'default';

    const messages = Array.isArray(value.messages) ? value.messages : [];
    for (const msg of messages) {
      const waId = String(msg?.from || '').trim();
      const messageText = messageTextFromMessage(msg);
      if (!waId || !messageText) continue;

      const tsRaw = String(msg?.timestamp || '').trim();
      const tsNumber = Number(tsRaw);
      const receivedAt = Number.isFinite(tsNumber) && tsNumber > 0
        ? new Date(tsNumber * 1000).toISOString()
        : new Date().toISOString();

      out.push({
        json: {
          event_type: 'inbound',
          event_id: String(msg?.id || (waId + '-' + Date.now())).trim(),
          wa_id: waId,
          telefone: waId,
          message_text: messageText,
          tenant_id: tenantId,
          jurisdicao: 'BR',
          canal: 'WHATSAPP',
          received_at: receivedAt,
          phone_number_id: phoneNumberId,
          payload: {
            entry_id: entry?.id,
            change_field: change?.field,
            message_type: msg?.type,
            raw_message: msg,
          },
        },
      });
    }

    const statuses = Array.isArray(value.statuses) ? value.statuses : [];
    for (const st of statuses) {
      const messageId = String(st?.id || '').trim();
      const waId = String(st?.recipient_id || '').trim();
      const status = String(st?.status || '').trim();
      const tsRaw = String(st?.timestamp || '').trim();
      const tsNumber = Number(tsRaw);
      const timestamp = Number.isFinite(tsNumber) && tsNumber > 0
        ? new Date(tsNumber * 1000).toISOString()
        : new Date().toISOString();

      if (!messageId || !status) continue;

      out.push({
        json: {
          event_type: 'status',
          event_id: messageId + ':' + status + ':' + timestamp,
          message_id: messageId,
          wa_id: waId,
          status,
          timestamp,
          tenant_id: tenantId,
          payload: {
            entry_id: entry?.id,
            change_field: change?.field,
            raw_status: st,
          },
        },
      });
    }
  }
}

return out;

const output = [];
for (const item of $input.all()) {
  const d = item.json || {};
  if (String(d.status || '').toLowerCase() !== 'ok') continue;

  const to = String(d.wa_id || '').trim();
  const text = String(d.mensagem || '').trim();
  if (!to || !text) continue;

  output.push({
    json: {
      to,
      phone_number_id: String(d.phone_number_id || $env.WHATSAPP_PHONE_NUMBER_ID || '').trim(),
      text,
      lara_acao: String(d.acao || ''),
      lara_status: String(d.status || ''),
      codcli: d.codcli || '',
      cliente: d.cliente || '',
      event_id: String(d.event_id || ''),
    },
  });
}

return output;
